class Solution:
    def climbStairs(self, n: int) -> int:
        def mul(A, B):
            return [
                [A[0][0]*B[0][0] + A[0][1]*B[1][0], A[0][0]*B[0][1] + A[0][1]*B[1][1]],
                [A[1][0]*B[0][0] + A[1][1]*B[1][0], A[1][0]*B[0][1] + A[1][1]*B[1][1]],
            ]
        def matpow(A, p):
            R = [[1, 0], [0, 1]]
            while p:
                if p & 1:
                    R = mul(R, A)
                A = mul(A, A)
                p >>= 1
            return R
        if n == 0:
            return 1
        M = matpow([[1, 1], [1, 0]], n)
        return M[0][0]

